use pyo3::prelude::*;

#[pyfunction]
fn cpu_heavy_task(py: Python<'_>, data: Vec<f64>) -> PyResult<f64> {
    // Release GIL for CPU-bound work
    let result = py.allow_threads(|| {
        data.iter()
            .map(|x| x.sin() * x.cos())
            .sum::<f64>()
    });
    Ok(result)
}
